```typescript
import { NextResponse } from "next/server";
import { z } from "zod";
import { prisma } from "@rlm-saas/database"; // Adjust the import based on your project structure
import { requireAuth } from "@/lib/auth"; // Ensure the user is authenticated

// Define the Zod schema for query parameters
const querySchema = z.object({
  limit: z.number().optional().default(50), // Default limit to 50
  offset: z.number().optional().default(0), // Default offset to 0
});

export async function GET(request: Request) {
  try {
    // Authenticate the user
    const user = await requireAuth();

    // Parse and validate query parameters
    const url = new URL(request.url);
    const queryParams = querySchema.parse({
      limit: Number(url.searchParams.get("limit")),
      offset: Number(url.searchParams.get("offset")),
    });

    // Fetch users from the database with pagination
    const users = await prisma.user.findMany({
      skip: queryParams.offset,
      take: queryParams.limit,
    });

    // Return the list of users
    return NextResponse.json({ success: true, data: users });
  } catch (error) {
    // Handle errors (e.g., validation errors, database errors)
    return NextResponse.json({ success: false, message: error.message }, { status: 400 });
  }
}
```

